            (fun v0 v1 v2 -> SubobjectClassifierNode.SubobjectClassifierSeq2 (v0, v1, v2))) ]

do subobjectClassifierRefImpl.Value <- subobjectClassifierParser

let private powerObjectParser : Parser<PowerObjectNode, unit> =
    choice [
        attempt (        pipe4
            (pstring "P")
            (pstring "(")
            (musicalObjectRef)
            (pstring ")")
            (fun v0 v1 v2 v3 -> PowerObjectNode.PowerObjectSeq1 (v0, v1, v2, v3)))
        attempt (        pipe4
            (pstring "power")
            (pstring "(")
            (musicalObjectRef)
            (pstring ")")
            (fun v0 v1 v2 v3 -> PowerObjectNode.PowerObjectSeq2 (v0, v1, v2, v3)))
        attempt (        pipe3
            (pstring "subobjects")
            (pstring "of")
            (musicalObjectRef)
            (fun v0 v1 v2 -> PowerObjectNode.PowerObjectSeq3 (v0, v1, v2))) ]

do powerObjectRefImpl.Value <- powerObjectParser

let private internalHomParser : Parser<InternalHomNode, unit> =
    choice [
        attempt (        pipe2
            (pstring "Hom")
            (
            pipe5
                (pstring "(")
                (musicalObjectRef)
                (pstring ",")
                (musicalObjectRef)
                (pstring ")")
                (fun t0 t1 t2 t3 t4 -> (t0, t1, t2, t3, t4))            )
            (fun v0 (v1, v2, v3, v4, v5) -> InternalHomNode.InternalHomSeq1 (v0, v1, v2, v3, v4, v5)))
        attempt (        pipe3
            (musicalObjectRef)
            (pstring "=>")
            (musicalObjectRef)
            (fun v0 v1 v2 -> InternalHomNode.InternalHomSeq2 (v0, v1, v2))) ]

do internalHomRefImpl.Value <- internalHomParser

let private sheafOperationParser : Parser<SheafOperationNode, unit> =
    choice [
        attempt (sheafDefinitionRef |>> SheafOperationNode.SheafDefinition)
        attempt (sheafRestrictionRef |>> SheafOperationNode.SheafRestriction)
        attempt (sheafGluingRef |>> SheafOperationNode.SheafGluing) ]

do sheafOperationRefImpl.Value <- sheafOperationParser

let private sheafDefinitionParser : Parser<SheafDefinitionNode, unit> =
    choice [
        attempt (        pipe4
            (pstring "sheaf")
            (sheafNameRef)
            (pstring "on")
            (spaceSpecRef)
            (fun v0 v1 v2 v3 -> SheafDefinitionNode.SheafDefinitionSeq1 (v0, v1, v2, v3)))
        attempt (        pipe2
            (pstring "define")
            (
            pipe5
                (pstring "sheaf")
                (sheafNameRef)
                (pstring "{")
                (sectionMappingRef)
                (pstring "}")
                (fun t0 t1 t2 t3 t4 -> (t0, t1, t2, t3, t4))            )
            (fun v0 (v1, v2, v3, v4, v5) -> SheafDefinitionNode.SheafDefinitionSeq2 (v0, v1, v2, v3, v4, v5))) ]

do sheafDefinitionRefImpl.Value <- sheafDefinitionParser

let private sheafNameParser : Parser<SheafNameNode, unit> =
    identifierRef |>> SheafNameNode.SheafName

do sheafNameRefImpl.Value <- sheafNameParser

let private spaceSpecParser : Parser<SpaceSpecNode, unit> =
    choice [
        attempt (pstring "fretboard" >>% SpaceSpecNode.Fretboard)
        attempt (pstring "circle_of_fifths" >>% SpaceSpecNode.CircleUnderofUnderfifths)
        attempt (pstring "tonnetz" >>% SpaceSpecNode.Tonnetz)
        attempt (pstring "pitch_class_space" >>% SpaceSpecNode.PitchUnderclassUnderspace)
        attempt (identifierRef |>> SpaceSpecNode.Identifier) ]

do spaceSpecRefImpl.Value <- spaceSpecParser

let private sectionMappingParser : Parser<SectionMappingNode, unit> =
    pipe2
        (sectionRuleRef)
        (many ((        pipe2
            (pstring ";")
            (sectionRuleRef)
            (fun t0 t1 -> (t0, t1)))))
        (fun v0 v1 -> SectionMappingNode.SectionMapping (v0, v1))
do sectionMappingRefImpl.Value <- sectionMappingParser

let private sectionRuleParser : Parser<SectionRuleNode, unit> =
    pipe3
        (openSetRef)
        (pstring "->")
        (musicalObjectRef)
        (fun v0 v1 v2 -> SectionRuleNode.SectionRule (v0, v1, v2))
do sectionRuleRefImpl.Value <- sectionRuleParser

let private openSetParser : Parser<OpenSetNode, unit> =
    identifierRef |>> OpenSetNode.OpenSet

do openSetRefImpl.Value <- openSetParser

let private sheafRestrictionParser : Parser<SheafRestrictionNode, unit> =
    choice [
        attempt (        pipe3
            (sheafNameRef)
            (pstring "|")
            (openSetRef)
            (fun v0 v1 v2 -> SheafRestrictionNode.SheafRestrictionSeq1 (v0, v1, v2)))
        attempt (        pipe4
            (pstring "restrict")
            (sheafNameRef)
            (pstring "to")
            (openSetRef)
            (fun v0 v1 v2 v3 -> SheafRestrictionNode.SheafRestrictionSeq2 (v0, v1, v2, v3))) ]

do sheafRestrictionRefImpl.Value <- sheafRestrictionParser

let private sheafGluingParser : Parser<SheafGluingNode, unit> =
    choice [
        attempt (        pipe4
            (pstring "glue")
            (pstring "{")
            (sectionListRef)
            (pstring "}")
            (fun v0 v1 v2 v3 -> SheafGluingNode.SheafGluingSeq1 (v0, v1, v2, v3)))
        attempt (        pipe4
            (pstring "glue")
            (sectionListRef)
            (pstring "along")
            (gluingDataRef)
            (fun v0 v1 v2 v3 -> SheafGluingNode.SheafGluingSeq2 (v0, v1, v2, v3))) ]

do sheafGluingRefImpl.Value <- sheafGluingParser

let private sectionListParser : Parser<SectionListNode, unit> =
    pipe2
        (musicalObjectRef)
        (many ((        pipe2
            (pstring ",")
            (musicalObjectRef)
            (fun t0 t1 -> (t0, t1)))))
        (fun v0 v1 -> SectionListNode.SectionList (v0, v1))
do sectionListRefImpl.Value <- sectionListParser

let private gluingDataParser : Parser<GluingDataNode, unit> =
    pipe4
        (pstring "{")
        (gluingRuleRef)
        (many ((        pipe2
            (pstring ";")
            (gluingRuleRef)
            (fun t0 t1 -> (t0, t1)))))
        (pstring "}")
        (fun v0 v1 v2 v3 -> GluingDataNode.GluingData (v0, v1, v2, v3))
do gluingDataRefImpl.Value <- gluingDataParser

let private gluingRuleParser : Parser<GluingRuleNode, unit> =
    pipe5
        (openSetRef)
        (pstring "∩")
        (openSetRef)
        (pstring "->")
        (morphismExpressionRef)
        (fun v0 v1 v2 v3 v4 -> GluingRuleNode.GluingRule (v0, v1, v2, v3, v4))
do gluingRuleRefImpl.Value <- gluingRuleParser

let private identifierParser : Parser<IdentifierNode, unit> =
    pipe2
        (letterRef)
        (many (choice [ attempt (letterRef |>> (fun _ -> "")); attempt (digitRef |>> (fun _ -> "")); attempt (pstring "_" |>> (fun _ -> "")) ]))
        (fun v0 v1 -> IdentifierNode.Identifier (v0, v1))
do identifierRefImpl.Value <- identifierParser

let private integerParser : Parser<IntegerNode, unit> =
    pipe3
        (opt (pstring "-"))
        (digitRef)
        (many (digitRef))
        (fun v0 v1 v2 -> IntegerNode.Integer (v0, v1, v2))
do integerRefImpl.Value <- integerParser

let private digitParser : Parser<DigitNode, unit> =
    choice [
        attempt (pstring "0" >>% DigitNode.N0)
        attempt (pstring "1" >>% DigitNode.N1)
        attempt (pstring "2" >>% DigitNode.N2)
        attempt (pstring "3" >>% DigitNode.N3)
        attempt (pstring "4" >>% DigitNode.N4)
        attempt (pstring "5" >>% DigitNode.N5)
        attempt (pstring "6" >>% DigitNode.N6)
        attempt (pstring "7" >>% DigitNode.N7)
        attempt (pstring "8" >>% DigitNode.N8)
        attempt (pstring "9" >>% DigitNode.N9) ]

do digitRefImpl.Value <- digitParser

/// Parse GrothendieckOperations from a string. Returns Ok or Error.
let parse (input: string) : Result<GrothendieckCommandNode, string> =
    match run (grothendieckCommandParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
